// Construye el mensaje de alerta para el dueño
const items = $input.all().map(i => i.json);

const lista = items.map(item => {
  const pct = Math.round((item.cantidad / item.stock_minimo) * 100);
  const emoji = pct < 30 ? '🔴' : pct < 60 ? '🟡' : '🟢';
  return `${emoji} *${item.ingrediente}*: ${item.cantidad} ${item.unidad} (mínimo: ${item.stock_minimo} ${item.unidad})`;
}).join('\n');

const mensaje = `⚠️ *ALERTA DE INVENTARIO*

Los siguientes ingredientes necesitan reposición:

${lista}

📋 Se ha generado la lista de compras automáticamente.
Revisa el sistema para ver el detalle.`;

return [{ json: { mensaje, items, fecha: new Date().toISOString() } }];

// Genera una orden de compra por proveedor
const items = $input.first().json.items;

// Agrupar por proveedor
const porProveedor = {};
items.forEach(item => {
  const key = item.proveedor_id || 'sin_proveedor';
  if (!porProveedor[key]) {
    porProveedor[key] = { proveedor: item.proveedor_nombre || 'Sin proveedor', tel: item.proveedor_tel, items: [] };
  }
  const cantidadSugerida = item.stock_minimo * 3; // Comprar para 3 veces el mínimo
  porProveedor[key].items.push({
    ingrediente: item.ingrediente,
    cantidadActual: item.cantidad,
    unidad: item.unidad,
    cantidadSugerida
  });
});

return Object.values(porProveedor).map(p => ({ json: p }));
